#include <bits/stdc++.h>
using namespace std;
unordered_map<string,int> mp,mp2;
int n,m,l,ans,mn;
string s1[100005];
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		string s;
		cin>>s;
		mp[s]=1;
	}
	cin>>m;
	l=1;
	for(int i=1;i<=m;i++)
	{
		cin>>s1[i];
		if(mp.count(s1[i])&&(!mp2.count(s1[i])))
		{
			ans++;
			mn=0x3f3f3f3f;
//			cout<<ans<<' '<<i<<'\n';
		}
		mp2[s1[i]]++;
		while(l<=i)
		{
			if(mp2[s1[l]]==1&&mp.count(s1[l])) break;
			mp2[s1[l]]--;
			l++;
		}
//		cout<<ans<<" "<<l<<" "<<i<<'\n';
		mn=min(mn,i-l+1);
	}
	cout<<ans<<"\n"<<mn;
	return 0;
}
